using sv_564cd736b60740cb9645d54b0896bfee.Models;

namespace sv_564cd736b60740cb9645d54b0896bfee.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella, basil, and San Marzano tomatoes.", 30),
            new(2, "Spaghetti Carbonara", "Creamy pasta with guanciale, egg yolk, Pecorino Romano, and black pepper.", 25),
            new(3, "Tiramisu", "Layered dessert with espresso-soaked ladyfingers and mascarpone cream.", 45),
            new(4, "Risotto ai Funghi", "Slow-cooked Arborio rice with porcini mushrooms and Parmesan.", 40),
        },
        [2] = new List<Recipe>
        {
            new(5, "Pad Thai", "Stir-fried rice noodles with shrimp, tofu, peanuts, and tamarind sauce.", 20),
            new(6, "Green Curry", "Coconut milk curry with Thai basil, bamboo shoots, and chicken.", 35),
            new(7, "Tom Yum Soup", "Spicy and sour soup with lemongrass, galangal, and prawns.", 25),
            new(8, "Mango Sticky Rice", "Sweet glutinous rice with fresh mango and coconut cream.", 50),
        },
        [3] = new List<Recipe>
        {
            new(9, "Tacos al Pastor", "Marinated pork tacos with pineapple, cilantro, and onion.", 60),
            new(10, "Guacamole", "Fresh avocado dip with lime, jalapeño, tomato, and cilantro.", 10),
            new(11, "Enchiladas Verdes", "Corn tortillas filled with chicken, topped with tomatillo salsa.", 45),
            new(12, "Churros", "Fried dough pastry dusted with cinnamon sugar, served with chocolate sauce.", 30),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        // Simulate a slow API call
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_564cd736b60740cb9645d54b0896bfee.Models
@using sv_564cd736b60740cb9645d54b0896bfee.Services
@implements IDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes...</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in DisplayedRecipes)
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;

    private CancellationTokenSource? _cts;

    private IEnumerable<Recipe> DisplayedRecipes
    {
        get
        {
            if (_recipes is null) return Enumerable.Empty<Recipe>();

            return Sort?.ToLowerInvariant() switch
            {
                "newest" => _recipes.OrderByDescending(r => r.Id),
                "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes),
                _ => _recipes,
            };
        }
    }

    protected override async Task OnParametersSetAsync()
    {
        // Only reload data when the cuisine changes, not when sort changes
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var cancellationToken = _cts.Token;

        _error = null;

        if (_recipes is not null)
        {
            _isRefreshing = true;
        }

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, cancellationToken);

            // Check cancellation after await in case a newer request superseded this one
            cancellationToken.ThrowIfCancellationRequested();

            _recipes = results;
            _loadedCuisineId = CuisineId;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
        {
            // Request was superseded by a newer one or component disposed — do nothing
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
            _isRefreshing = false;
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error fetching recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
            _isRefreshing = false;
        }
    }

    private async Task Retry()
    {
        _error = null;
        await LoadRecipesAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

